from Misc import *
from Player import *
from Journal import *
import time

stats = {
    "hits":    0,
    "misses":  0,
    "spells":  0,
    "potions": 0,
    "damage_dealt":    0,
    "damage_received": 0,
}

Journal.Clear()
start = time.time()
was_alive = not Player.IsGhost
Misc.SendMessage("PvP Analyzer avviato. Inizia il match!", 68)

while True:
    entries_j = Journal.GetJournalEntry(-1)
    for je in entries_j:
        t = je.Text
        if "You hit" in t:
            stats["hits"] += 1
        elif "You miss" in t or "You fail" in t:
            stats["misses"] += 1
        if "casts" in t.lower() or "You cast" in t:
            stats["spells"] += 1
        if "You drink" in t or "potion" in t.lower():
            stats["potions"] += 1
        if "You are hit" in t:
            try:
                parts = [p for p in t.split() if p.isdigit()]
                if parts:
                    stats["damage_received"] += int(parts[0])
            except:
                pass
        if "You hit" in t:
            try:
                parts = [p for p in t.split() if p.isdigit()]
                if parts:
                    stats["damage_dealt"] += int(parts[0])
            except:
                pass
    Journal.Clear()
    is_dead = Player.IsGhost
    if was_alive and is_dead:
        elapsed = int(time.time() - start)
        Misc.SendMessage("=== MATCH REPORT ===", 33)
        Misc.SendMessage("Durata: " + str(elapsed) + "s", 68)
        Misc.SendMessage("Colpi: " + str(stats["hits"]) + " | Mancati: " + str(stats["misses"]), 68)
        Misc.SendMessage("Spell: " + str(stats["spells"]) + " | Pozioni: " + str(stats["potions"]), 68)
        Misc.SendMessage("Danno inflitto: " + str(stats["damage_dealt"]), 68)
        Misc.SendMessage("Danno subito: " + str(stats["damage_received"]), 68)
        if stats["hits"] + stats["misses"] > 0:
            acc = int(100 * stats["hits"] / (stats["hits"] + stats["misses"]))
            Misc.SendMessage("Accuratezza: " + str(acc) + "%", 68)
        break
    was_alive = not is_dead
    Misc.Pause(300)

