import time
LOG_PATH = r"C:\Users\thebe\Desktop\scripts\The Miracle\Data\Plugins\RazorEnhanced\Scripts\AntiMacroSniffer_log.txt"
KEYWORDS = ["antimacro", "controllo antimacro", "anti macro"]
campione_n = 0
last_gump_id = None
keyword_time = None
resend_count = {}
def ts():
    return time.strftime("%H:%M:%S") + ".{:03d}".format(int(time.time() * 1000) % 1000)
def hx(v):
    try:
        return hex(int(v))
    except Exception:
        return repr(v)
def log_line(msg):
    line = "[{}] {}".format(ts(), msg)
    Misc.SendMessage(line, 68)
    try:
        with open(LOG_PATH, "a", encoding="utf-8") as f:
            f.write(line + "\n")
    except Exception as e:
        Misc.SendMessage("[Sniffer] ERRORE scrittura log: {}".format(e), 33)
def write_player(f):
    try:
        f.write("  Player : {}  HP {}/{}  MP {}/{}  Stam {}/{}\n".format(Player.Name, Player.Hits, Player.HitsMax, Player.Mana, Player.ManaMax, Player.Stam, Player.StamMax))
        try:
            pos = Player.Position
            f.write("  Pos    : ({}, {}, {})  Map={}\n".format(pos.X, pos.Y, pos.Z, Player.Map))
        except Exception as e:
            f.write("  Pos    : N/A ({})\n".format(e))
    except Exception as e:
        f.write("  Player : N/A ({})\n".format(e))
def write_gump_detail(f, gid, prefix="    "):
    try:
        gd = Gumps.GetGumpData(gid)
        f.write("{}GUMP_ID [param]    = {}\n".format(prefix, hx(gid)))
        try:
            f.write("{}GUMP_ID [GumpData] = {}\n".format(prefix, hx(gd.gumpId)))
            if int(gid) != int(gd.gumpId):
                f.write("{}!! DISCREPANZA tra param e GumpData.gumpID !!\n".format(prefix))
        except Exception as e:
            f.write("{}GUMP_ID [GumpData] = N/A ({})\n".format(prefix, e))
        f.write("{}Serial  = {}\n".format(prefix, hx(gd.serial)))
        f.write("{}Pos     = ({}, {})\n".format(prefix, gd.x, gd.y))
        strs = gd.gumpStrings
        if strs:
            f.write("{}Strings ({}):\n".format(prefix, len(strs)))
            for i, s in enumerate(strs):
                f.write("{}  [{}] {!r}\n".format(prefix, i, s))
        else:
            f.write("{}Strings : (nessuna)\n".format(prefix))
        layout = gd.gumpLayout
        if layout:
            f.write("{}Layout:\n{}\n".format(prefix, layout))
        else:
            f.write("{}Layout  : (vuoto)\n".format(prefix))
    except Exception as e:
        f.write("{}!! Errore write_gump_detail({}): {}\n".format(prefix, hx(gid), e))
def write_all_gumps(f, title="Gump corrente"):
    try:
        gid = Gumps.CurrentGump()
        if gid == 0:
            f.write("  {}: (nessun gump aperto)
".format(title))
            return
        f.write("  {} (gump corrente):
".format(title))
        write_gump_detail(f, gid, "    ")
    except Exception as e:
        f.write("  Errore write_all_gumps: {}
".format(e))
def log_campione(label, gid):
    global campione_n, keyword_time, resend_count
    campione_n += 1
    gk = str(gid)
    resend_count[gk] = resend_count.get(gk, 0) + 1
    rc = resend_count[gk]
    try:
        with open(LOG_PATH, "a", encoding="utf-8") as f:
            f.write("\n" + "=" * 60 + "\n")
            f.write("CAMPIONE #{}  [{}]  {}  (apparizione #{} di questo gumpID)\n".format(campione_n, label, ts(), rc))
            if keyword_time is not None:
                delta = time.time() - keyword_time
                f.write("  Delta da keyword : {:.3f}s\n".format(delta))
            else:
                f.write("  Delta da keyword : (non rilevata)\n")
            write_player(f)
            f.write("  == Gump rilevato (CurrentGump) ==\n")
            write_gump_detail(f, gid, "    ")
            write_all_gumps(f)
    except Exception as e:
        Misc.SendMessage("[Sniffer] Errore log_campione: {}".format(e), 33)
def log_keyword_event(kw):
    global keyword_time
    keyword_time = time.time()
    try:
        with open(LOG_PATH, "a", encoding="utf-8") as f:
            f.write("\n" + "*" * 60 + "\n")
            f.write("*** KEYWORD '{}' rilevata nel journal   {} ***\n".format(kw, ts()))
            f.write("*" * 60 + "\n")
            write_player(f)
            write_all_gumps(f, "Gump aperti al momento del keyword")
    except Exception as e:
        Misc.SendMessage("[Sniffer] Errore log_keyword: {}".format(e), 33)
def log_gump_close(gid):
    try:
        with open(LOG_PATH, "a", encoding="utf-8") as f:
            gk = str(gid)
            rc = resend_count.get(gk, 0)
            delta_str = ""
            if keyword_time is not None:
                delta_str = "  delta_da_keyword={:.3f}s".format(time.time() - keyword_time)
            f.write("\n[{}] Gump chiuso: {}  (era apparso {} volte){}  \n".format(ts(), hx(gid), rc, delta_str))
            write_player(f)
            write_all_gumps(f, "Gump ancora aperti dopo chiusura")
    except Exception as e:
        Misc.SendMessage("[Sniffer] Errore log_close: {}".format(e), 33)
def journal_ha_trigger():
    for kw in KEYWORDS:
        try:
            if Journal.Search(kw):
                return kw
        except Exception:
            pass
    return None
with open(LOG_PATH, "a", encoding="utf-8") as _f:
    _f.write("\n" + "#" * 60 + "\n")
    _f.write("# AntiMacroSniffer v2 \n")
    _f.write("#" * 60 + "\n")
while True:
